{
  "name": "STL Editor Pro",
  "description": "A high-performance web-based STL editor and visualizer inspired by numpy-stl. Edit, transform, and analyze 3D mesh files with ease.",
  "requestFramePermissions": []
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Vector3 {
  x: number;
  y: number;
  z: number;
}

export interface TransformationState {
  position: Vector3;
  rotation: Vector3;
  scale: number;
}

export interface MeshStats {
  volume: number;
  surfaceArea: number;
  boundingBox: {
    min: Vector3;
    max: Vector3;
    size: Vector3;
  };
  triangleCount: number;
}

export interface AppState {
  isLoaded: boolean;
  fileName: string | null;
  transform: TransformationState;
  stats: MeshStats | null;
  viewMode: 'wireframe' | 'solid' | 'points';
  color: string;
}

import * as THREE from 'three';
import { STLLoader } from 'three/examples/jsm/loaders/STLLoader';
import { STLExporter } from 'three/examples/jsm/exporters/STLExporter';
import { MeshStats, Vector3 } from '../types';

export class STLService {
  private loader: STLLoader;
  private exporter: STLExporter;

  constructor() {
    this.loader = new STLLoader();
    this.exporter = new STLExporter();
  }

  async loadFromBuffer(buffer: ArrayBuffer): Promise<THREE.BufferGeometry> {
    return this.loader.parse(buffer);
  }

  exportMesh(mesh: THREE.Mesh): Blob {
    const result = this.exporter.parse(mesh, { binary: true });
    return new Blob([result], { type: 'application/octet-stream' });
  }

  calculateStats(geometry: THREE.BufferGeometry): MeshStats {
    if (!geometry.index && geometry.attributes.position.count === 0) {
        return this.getEmptyStats();
    }

    geometry.computeBoundingBox();
    const box = geometry.boundingBox!;
    const size = new THREE.Vector3();
    box.getSize(size);

    let volume = 0;
    let surfaceArea = 0;

    const pos = geometry.attributes.position;
    const faces = pos.count / 3;

    for (let i = 0; i < faces; i++) {
      const v1 = new THREE.Vector3().fromBufferAttribute(pos, i * 3 + 0);
      const v2 = new THREE.Vector3().fromBufferAttribute(pos, i * 3 + 1);
      const v3 = new THREE.Vector3().fromBufferAttribute(pos, i * 3 + 2);

      // Volume calculation using signed volume of tetrahedra
      volume += v1.dot(v2.cross(v3)) / 6.0;

      // Surface area calculation
      const edge1 = new THREE.Vector3().subVectors(v2, v1);
      const edge2 = new THREE.Vector3().subVectors(v3, v1);
      surfaceArea += edge1.cross(edge2).length() / 2.0;
    }

    return {
      volume: Math.abs(volume),
      surfaceArea: surfaceArea,
      triangleCount: faces,
      boundingBox: {
        min: { x: box.min.x, y: box.min.y, z: box.min.z },
        max: { x: box.max.x, y: box.max.y, z: box.max.z },
        size: { x: size.x, y: size.y, z: size.z }
      }
    };
  }

  private getEmptyStats(): MeshStats {
    return {
      volume: 0,
      surfaceArea: 0,
      triangleCount: 0,
      boundingBox: {
        min: { x: 0, y: 0, z: 0 },
        max: { x: 0, y: 0, z: 0 },
        size: { x: 0, y: 0, z: 0 }
      }
    };
  }
}

export const stlService = new STLService();

import React, { useEffect, useRef } from 'react';
import * as THREE from 'three';
import { OrbitControls } from 'three/examples/jsm/controls/OrbitControls';
import { AppState } from '../types';

interface ViewerProps {
  geometry: THREE.BufferGeometry | null;
  state: AppState;
}

const Viewer: React.FC<ViewerProps> = ({ geometry, state }) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const rendererRef = useRef<THREE.WebGLRenderer | null>(null);
  const meshRef = useRef<THREE.Mesh | null>(null);
  const sceneRef = useRef<THREE.Scene | null>(null);
  const cameraRef = useRef<THREE.PerspectiveCamera | null>(null);

  useEffect(() => {
    if (!containerRef.current) return;

    // Scene Setup
    const scene = new THREE.Scene();
    scene.background = new THREE.Color(0x0f172a);
    sceneRef.current = scene;

    // Camera
    const camera = new THREE.PerspectiveCamera(
      45,
      containerRef.current.clientWidth / containerRef.current.clientHeight,
      0.1,
      2000
    );
    camera.position.set(200, 200, 200);
    cameraRef.current = camera;

    // Renderer
    const renderer = new THREE.WebGLRenderer({ antialias: true });
    renderer.setSize(containerRef.current.clientWidth, containerRef.current.clientHeight);
    renderer.setPixelRatio(window.devicePixelRatio);
    containerRef.current.appendChild(renderer.domElement);
    rendererRef.current = renderer;

    // Controls
    const controls = new OrbitControls(camera, renderer.domElement);
    controls.enableDamping = true;

    // Lights
    const ambientLight = new THREE.AmbientLight(0xffffff, 0.5);
    scene.add(ambientLight);

    const directionalLight1 = new THREE.DirectionalLight(0xffffff, 0.8);
    directionalLight1.position.set(100, 100, 100);
    scene.add(directionalLight1);

    const directionalLight2 = new THREE.DirectionalLight(0xffffff, 0.5);
    directionalLight2.position.set(-100, -50, -100);
    scene.add(directionalLight2);

    // Helpers
    const gridHelper = new THREE.GridHelper(400, 40, 0x334155, 0x1e293b);
    scene.add(gridHelper);

    const axesHelper = new THREE.AxesHelper(100);
    scene.add(axesHelper);

    // Animation loop
    const animate = () => {
      requestAnimationFrame(animate);
      controls.update();
      renderer.render(scene, camera);
    };
    animate();

    const handleResize = () => {
      if (!containerRef.current || !cameraRef.current || !rendererRef.current) return;
      cameraRef.current.aspect = containerRef.current.clientWidth / containerRef.current.clientHeight;
      cameraRef.current.updateProjectionMatrix();
      rendererRef.current.setSize(containerRef.current.clientWidth, containerRef.current.clientHeight);
    };

    window.addEventListener('resize', handleResize);

    return () => {
      window.removeEventListener('resize', handleResize);
      renderer.dispose();
      if (containerRef.current) {
        // eslint-disable-next-line react-hooks/exhaustive-deps
        containerRef.current.removeChild(renderer.domElement);
      }
    };
  }, []);

  // Update Geometry and Transformations
  useEffect(() => {
    if (!sceneRef.current || !geometry) return;

    // Clear previous mesh
    if (meshRef.current) {
      sceneRef.current.remove(meshRef.current);
      meshRef.current.geometry.dispose();
      (meshRef.current.material as THREE.Material).dispose();
    }

    // Create Material based on view mode
    let material: THREE.Material;
    const materialProps = {
      color: state.color,
      flatShading: true,
      side: THREE.DoubleSide,
    };

    if (state.viewMode === 'wireframe') {
      material = new THREE.MeshBasicMaterial({ ...materialProps, wireframe: true });
    } else if (state.viewMode === 'points') {
        // Points rendering needs separate object usually, but for mesh editing we just show vertices
        material = new THREE.PointsMaterial({ color: state.color, size: 2 });
    } else {
      material = new THREE.MeshPhongMaterial({ ...materialProps, shininess: 30 });
    }

    // Add mesh to scene
    const mesh = new THREE.Mesh(geometry, material);

    // Auto-center geometry on load if not modified yet
    geometry.center();

    meshRef.current = mesh;
    sceneRef.current.add(mesh);

  }, [geometry, state.viewMode, state.color]);

  // Handle transformations
  useEffect(() => {
    if (!meshRef.current) return;

    meshRef.current.position.set(state.transform.position.x, state.transform.position.y, state.transform.position.z);
    meshRef.current.rotation.set(
      THREE.MathUtils.degToRad(state.transform.rotation.x),
      THREE.MathUtils.degToRad(state.transform.rotation.y),
      THREE.MathUtils.degToRad(state.transform.rotation.z)
    );
    meshRef.current.scale.setScalar(state.transform.scale);
  }, [state.transform]);

  return <div ref={containerRef} className="w-full h-full relative" />;
};

export default Viewer;

import React from 'react';
import { AppState, Vector3 } from '../types';
import { Settings, Info, Download, Trash2, Box, Layers, Move, RefreshCw, Maximize } from 'lucide-react';

interface ControlsProps {
  state: AppState;
  onTransformChange: (key: 'position' | 'rotation' | 'scale', value: any) => void;
  onViewModeChange: (mode: AppState['viewMode']) => void;
  onColorChange: (color: string) => void;
  onReset: () => void;
  onExport: () => void;
  onClear: () => void;
}

const ControlGroup: React.FC<{ title: string; icon: React.ReactNode; children: React.ReactNode }> = ({ title, icon, children }) => (
  <div className="mb-6 p-4 bg-slate-800/50 rounded-xl border border-slate-700/50">
    <div className="flex items-center gap-2 mb-4 text-slate-300 font-semibold text-sm uppercase tracking-wider">
      {icon}
      <span>{title}</span>
    </div>
    {children}
  </div>
);

const Slider: React.FC<{ label: string; value: number; min: number; max: number; step?: number; onChange: (v: number) => void }> = ({ label, value, min, max, step = 0.1, onChange }) => (
  <div className="mb-3">
    <div className="flex justify-between text-xs text-slate-400 mb-1">
      <span>{label}</span>
      <span className="font-mono">{value.toFixed(2)}</span>
    </div>
    <input
      type="range"
      min={min}
      max={max}
      step={step}
      value={value}
      onChange={(e) => onChange(parseFloat(e.target.value))}
      className="w-full h-1.5 bg-slate-700 rounded-lg appearance-none cursor-pointer accent-blue-500"
    />
  </div>
);

const Controls: React.FC<ControlsProps> = ({ state, onTransformChange, onViewModeChange, onColorChange, onReset, onExport, onClear }) => {
  if (!state.isLoaded) return (
      <div className="p-8 text-center text-slate-400">
          <Info className="mx-auto mb-4 opacity-50" size={48} />
          <p>Please upload an STL file to begin editing.</p>
      </div>
  );

  return (
    <div className="flex flex-col h-full overflow-y-auto px-4 py-6 scrollbar-hide">
      <div className="flex justify-between items-center mb-6">
        <h2 className="text-xl font-bold text-white flex items-center gap-2">
            <Box className="text-blue-400" />
            Editor
        </h2>
        <button onClick={onClear} className="p-2 text-slate-400 hover:text-red-400 transition-colors" title="Clear Canvas">
            <Trash2 size={18} />
        </button>
      </div>

      <ControlGroup title="Transform" icon={<Move size={16} />}>
        <div className="space-y-4">
          <div>
            <p className="text-[10px] text-slate-500 mb-2 font-bold">POSITION</p>
            <Slider label="X" value={state.transform.position.x} min={-100} max={100} onChange={(v) => onTransformChange('position', { ...state.transform.position, x: v })} />
            <Slider label="Y" value={state.transform.position.y} min={-100} max={100} onChange={(v) => onTransformChange('position', { ...state.transform.position, y: v })} />
            <Slider label="Z" value={state.transform.position.z} min={-100} max={100} onChange={(v) => onTransformChange('position', { ...state.transform.position, z: v })} />
          </div>
          <div>
            <p className="text-[10px] text-slate-500 mb-2 font-bold">ROTATION</p>
            <Slider label="RX" value={state.transform.rotation.x} min={-180} max={180} onChange={(v) => onTransformChange('rotation', { ...state.transform.rotation, x: v })} />
            <Slider label="RY" value={state.transform.rotation.y} min={-180} max={180} onChange={(v) => onTransformChange('rotation', { ...state.transform.rotation, y: v })} />
            <Slider label="RZ" value={state.transform.rotation.z} min={-180} max={180} onChange={(v) => onTransformChange('rotation', { ...state.transform.rotation, z: v })} />
          </div>
          <div>
            <p className="text-[10px] text-slate-500 mb-2 font-bold">UNIFORM SCALE</p>
            <Slider label="Scale" value={state.transform.scale} min={0.1} max={10} step={0.05} onChange={(v) => onTransformChange('scale', v)} />
          </div>
        </div>
      </ControlGroup>

      <ControlGroup title="Visuals" icon={<Layers size={16} />}>
        <div className="grid grid-cols-3 gap-2 mb-4">
          {(['solid', 'wireframe', 'points'] as const).map((mode) => (
            <button
              key={mode}
              onClick={() => onViewModeChange(mode)}
              className={`py-1.5 text-[10px] font-bold uppercase rounded border transition-all ${
                state.viewMode === mode
                  ? 'bg-blue-600 border-blue-500 text-white'
                  : 'bg-slate-700 border-slate-600 text-slate-400 hover:bg-slate-600'
              }`}
            >
              {mode}
            </button>
          ))}
        </div>
        <div className="flex items-center justify-between">
          <span className="text-xs text-slate-400">Mesh Color</span>
          <input
            type="color"
            value={state.color}
            onChange={(e) => onColorChange(e.target.value)}
            className="w-8 h-8 rounded bg-transparent border-none cursor-pointer"
          />
        </div>
      </ControlGroup>

      <ControlGroup title="Metadata" icon={<Info size={16} />}>
        {state.stats && (
          <div className="space-y-3 text-xs">
            <div className="flex justify-between border-b border-slate-700 pb-1">
              <span className="text-slate-500">Triangles</span>
              <span className="text-slate-300">{state.stats.triangleCount.toLocaleString()}</span>
            </div>
            <div className="flex justify-between border-b border-slate-700 pb-1">
              <span className="text-slate-500">Volume</span>
              <span className="text-slate-300">{(state.stats.volume * Math.pow(state.transform.scale, 3)).toFixed(2)} mm³</span>
            </div>
            <div className="flex justify-between border-b border-slate-700 pb-1">
              <span className="text-slate-500">Surface Area</span>
              <span className="text-slate-300">{(state.stats.surfaceArea * Math.pow(state.transform.scale, 2)).toFixed(2)} mm²</span>
            </div>
            <div className="flex justify-between border-b border-slate-700 pb-1">
              <span className="text-slate-500">Size (X/Y/Z)</span>
              <span className="text-slate-300">
                {(state.stats.boundingBox.size.x * state.transform.scale).toFixed(1)} x 
                {(state.stats.boundingBox.size.y * state.transform.scale).toFixed(1)} x 
                {(state.stats.boundingBox.size.z * state.transform.scale).toFixed(1)} mm
              </span>
            </div>
          </div>
        )}
      </ControlGroup>

      <div className="mt-auto pt-4 space-y-3">
        <button 
          onClick={onReset}
          className="w-full py-3 flex items-center justify-center gap-2 bg-slate-700 hover:bg-slate-600 text-white rounded-xl font-semibold transition-all"
        >
          <RefreshCw size={18} />
          Reset View
        </button>
        <button 
          onClick={onExport}
          className="w-full py-3 flex items-center justify-center gap-2 bg-blue-600 hover:bg-blue-500 text-white rounded-xl font-semibold shadow-lg shadow-blue-500/20 transition-all"
        >
          <Download size={18} />
          Export STL
        </button>
      </div>
    </div>
  );
};

export default Controls;

import React, { useState, useCallback, useRef } from 'react';
import * as THREE from 'three';
import { Upload, Box, Github, HelpCircle } from 'lucide-react';
import Viewer from './components/Viewer';
import Controls from './components/Controls';
import { AppState, TransformationState } from './types';
import { stlService } from './services/stlService';

const INITIAL_TRANSFORM: TransformationState = {
  position: { x: 0, y: 0, z: 0 },
  rotation: { x: 0, y: 0, z: 0 },
  scale: 1
};

const INITIAL_STATE: AppState = {
  isLoaded: false,
  fileName: null,
  transform: INITIAL_TRANSFORM,
  stats: null,
  viewMode: 'solid',
  color: '#3b82f6',
};

const App: React.FC = () => {
  const [state, setState] = useState<AppState>(INITIAL_STATE);
  const [geometry, setGeometry] = useState<THREE.BufferGeometry | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    try {
      const buffer = await file.arrayBuffer();
      const geo = await stlService.loadFromBuffer(buffer);
      const stats = stlService.calculateStats(geo);

      setGeometry(geo);
      setState(prev => ({
        ...prev,
        isLoaded: true,
        fileName: file.name,
        stats,
        transform: INITIAL_TRANSFORM
      }));
    } catch (err) {
      console.error("Error loading STL file:", err);
      alert("Error loading file. Please ensure it is a valid STL.");
    }
  };

  const handleTransformChange = (key: keyof TransformationState, value: any) => {
    setState(prev => ({
      ...prev,
      transform: {
        ...prev.transform,
        [key]: value
      }
    }));
  };

  const handleReset = () => {
    setState(prev => ({ ...prev, transform: INITIAL_TRANSFORM }));
  };

  const handleClear = () => {
    setGeometry(null);
    setState(INITIAL_STATE);
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const handleExport = () => {
    if (!geometry) return;

    // Apply current transforms to a temporary mesh for export
    const tempMesh = new THREE.Mesh(geometry.clone());
    tempMesh.position.set(state.transform.position.x, state.transform.position.y, state.transform.position.z);
    tempMesh.rotation.set(
      THREE.MathUtils.degToRad(state.transform.rotation.x),
      THREE.MathUtils.degToRad(state.transform.rotation.y),
      THREE.MathUtils.degToRad(state.transform.rotation.z)
    );
    tempMesh.scale.setScalar(state.transform.scale);
    tempMesh.updateMatrixWorld();

    const blob = stlService.exportMesh(tempMesh);
    const link = document.createElement('a');
    link.href = URL.createObjectURL(blob);
    link.download = `edited_${state.fileName || 'model.stl'}`;
    link.click();
  };

  return (
    <div className="flex h-screen w-screen bg-slate-950 text-slate-50 overflow-hidden select-none">
      {/* Sidebar */}
      <aside className="w-80 h-full bg-slate-900 border-r border-slate-800 z-10 shadow-2xl flex flex-col">
        <div className="p-6 border-b border-slate-800 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="bg-blue-600 p-2 rounded-lg">
                <Box size={20} className="text-white" />
            </div>
            <h1 className="font-bold text-lg tracking-tight">STLEdit <span className="text-blue-500">Pro</span></h1>
          </div>
        </div>

        <div className="flex-1 overflow-hidden">
          <Controls 
            state={state}
            onTransformChange={handleTransformChange}
            onViewModeChange={(mode) => setState(prev => ({ ...prev, viewMode: mode }))}
            onColorChange={(color) => setState(prev => ({ ...prev, color }))}
            onReset={handleReset}
            onExport={handleExport}
            onClear={handleClear}
          />
        </div>

        <div className="p-4 border-t border-slate-800 bg-slate-900/50 flex justify-around opacity-60">
            <button className="hover:text-blue-400 transition-colors"><Github size={18}/></button>
            <button className="hover:text-blue-400 transition-colors"><HelpCircle size={18}/></button>
        </div>
      </aside>

      {/* Main Area */}
      <main className="flex-1 relative bg-slate-950 overflow-hidden">
        {/* Floating Toolbar */}
        <div className="absolute top-6 left-6 z-20 flex gap-4">
            <div className="flex items-center gap-4 bg-slate-900/80 backdrop-blur-md border border-slate-700/50 px-4 py-2 rounded-2xl shadow-xl">
                <input
                    type="file"
                    accept=".stl"
                    onChange={handleFileUpload}
                    ref={fileInputRef}
                    className="hidden"
                    id="stl-upload"
                />
                <label 
                    htmlFor="stl-upload" 
                    className="flex items-center gap-2 text-sm font-semibold cursor-pointer text-slate-300 hover:text-white transition-colors"
                >
                    <Upload size={18} className="text-blue-500" />
                    {state.fileName ? 'Change File' : 'Upload STL'}
                </label>
                {state.fileName && (
                    <>
                        <div className="w-px h-4 bg-slate-700" />
                        <span className="text-xs text-slate-400 max-w-[150px] truncate">{state.fileName}</span>
                    </>
                )}
            </div>
        </div>

        {/* 3D Viewport */}
        <div className="w-full h-full">
          {state.isLoaded ? (
            <Viewer geometry={geometry} state={state} />
          ) : (
            <div className="w-full h-full flex flex-col items-center justify-center text-slate-500">
              <div className="w-24 h-24 mb-6 rounded-full bg-slate-900 flex items-center justify-center border border-slate-800 shadow-inner">
                <Upload size={32} className="opacity-20" />
              </div>
              <p className="text-lg font-medium">Ready to edit your 3D models</p>
              <p className="text-sm opacity-60">Drag and drop or click upload to begin</p>

              <div className="mt-12 grid grid-cols-2 gap-4">
                 <div className="p-4 rounded-xl border border-slate-800 bg-slate-900/30 text-center">
                    <p className="text-xs uppercase font-bold text-slate-600 mb-1">Compute</p>
                    <p className="text-slate-400 text-sm italic">Mesh Volume & Area</p>
                 </div>
                 <div className="p-4 rounded-xl border border-slate-800 bg-slate-900/30 text-center">
                    <p className="text-xs uppercase font-bold text-slate-600 mb-1">Transform</p>
                    <p className="text-slate-400 text-sm italic">Scale, Rotation, Pivot</p>
                 </div>
              </div>
            </div>
          )}
        </div>

        {/* View Info HUD */}
        {state.isLoaded && (
            <div className="absolute bottom-6 right-6 z-20 bg-slate-900/40 backdrop-blur-sm border border-slate-800/50 px-3 py-1.5 rounded-lg text-[10px] text-slate-500 pointer-events-none font-mono">
                RENDER: WebGL 2.0 | FPS: 60 | UNITS: MM
            </div>
        )}
      </main>
    </div>
  );
};

export default App;

export interface Vector3 {
  x: number;
  y: number;
  z: number;
}

export interface TransformationState {
  position: Vector3;
  rotation: Vector3;
  scale: number;
}

export interface SliceState {
  enabled: boolean;
  axis: 'x' | 'y' | 'z';
  position: number;
}

export interface MeshStats {
  volume: number;
  surfaceArea: number;
  boundingBox: {
    min: Vector3;
    max: Vector3;
    size: Vector3;
  };
  triangleCount: number;
}

export interface AppState {
  isLoaded: boolean;
  fileName: string | null;
  transform: TransformationState;
  slice: SliceState;
  stats: MeshStats | null;
  viewMode: 'wireframe' | 'solid' | 'points';
  color: string;
  aiAnalysis?: string;
}

import * as THREE from 'three';
import { STLLoader } from 'three/examples/jsm/loaders/STLLoader';
import { STLExporter } from 'three/examples/jsm/exporters/STLExporter';
import { MeshStats, Vector3 } from '../types';
import { GoogleGenAI } from "@google/genai";

export class STLService {
  private loader: STLLoader;
  private exporter: STLExporter;

  constructor() {
    this.loader = new STLLoader();
    this.exporter = new STLExporter();
  }

  async loadFromBuffer(buffer: ArrayBuffer): Promise<THREE.BufferGeometry> {
    return this.loader.parse(buffer);
  }

  exportMesh(mesh: THREE.Mesh): Blob {
    const result = this.exporter.parse(mesh, { binary: true });
    return new Blob([result], { type: 'application/octet-stream' });
  }

  async analyzeWithAI(stats: MeshStats): Promise<string> {
    const ai = new GoogleGenAI({ apiKey: (process.env as any).API_KEY });
    const prompt = `Analyze this 3D model (STL) based on its stats for 3D printing:
      - Triangle Count: ${stats.triangleCount}
      - Volume: ${stats.volume.toFixed(2)} mm³
      - Dimensions: ${stats.boundingBox.size.x.toFixed(1)} x ${stats.boundingBox.size.y.toFixed(1)} x ${stats.boundingBox.size.z.toFixed(1)} mm
      Give a short professional assessment (max 3 sentences) in German about printability and if it should be split.`;

    try {
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
      });
      return response.text || "Analyse fehlgeschlagen.";
    } catch (e) {
      return "KI Analyse derzeit nicht verfügbar.";
    }
  }

  calculateStats(geometry: THREE.BufferGeometry): MeshStats {
    if (!geometry.index && geometry.attributes.position.count === 0) {
        return this.getEmptyStats();
    }

    geometry.computeBoundingBox();
    const box = geometry.boundingBox!;
    const size = new THREE.Vector3();
    box.getSize(size);

    let volume = 0;
    let surfaceArea = 0;

    const pos = geometry.attributes.position;
    const faces = pos.count / 3;

    for (let i = 0; i < faces; i++) {
      const v1 = new THREE.Vector3().fromBufferAttribute(pos, i * 3 + 0);
      const v2 = new THREE.Vector3().fromBufferAttribute(pos, i * 3 + 1);
      const v3 = new THREE.Vector3().fromBufferAttribute(pos, i * 3 + 2);

      volume += v1.dot(v2.cross(v3)) / 6.0;

      const edge1 = new THREE.Vector3().subVectors(v2, v1);
      const edge2 = new THREE.Vector3().subVectors(v3, v1);
      surfaceArea += edge1.cross(edge2).length() / 2.0;
    }

    return {
      volume: Math.abs(volume),
      surfaceArea: surfaceArea,
      triangleCount: faces,
      boundingBox: {
        min: { x: box.min.x, y: box.min.y, z: box.min.z },
        max: { x: box.max.x, y: box.max.y, z: box.max.z },
        size: { x: size.x, y: size.y, z: size.z }
      }
    };
  }

  private getEmptyStats(): MeshStats {
    return {
      volume: 0,
      surfaceArea: 0,
      triangleCount: 0,
      boundingBox: {
        min: { x: 0, y: 0, z: 0 },
        max: { x: 0, y: 0, z: 0 },
        size: { x: 0, y: 0, z: 0 }
      }
    };
  }
}

