import React, { useEffect, useRef } from 'react';
import * as THREE from 'three';
import { OrbitControls } from 'three/examples/jsm/controls/OrbitControls';
import { AppState } from '../types';

interface ViewerProps {
  geometry: THREE.BufferGeometry | null;
  state: AppState;
}

const Viewer: React.FC<ViewerProps> = ({ geometry, state }) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const rendererRef = useRef<THREE.WebGLRenderer | null>(null);
  const meshRef = useRef<THREE.Mesh | null>(null);
  const sceneRef = useRef<THREE.Scene | null>(null);
  const cameraRef = useRef<THREE.PerspectiveCamera | null>(null);
  const planeHelperRef = useRef<THREE.Mesh | null>(null);

  useEffect(() => {
    if (!containerRef.current) return;

    const scene = new THREE.Scene();
    scene.background = new THREE.Color(0x0f172a);
    sceneRef.current = scene;

    const camera = new THREE.PerspectiveCamera(
      45,
      containerRef.current.clientWidth / containerRef.current.clientHeight,
      0.1,
      2000
    );
    camera.position.set(200, 200, 200);
    cameraRef.current = camera;

    const renderer = new THREE.WebGLRenderer({ antialias: true });
    renderer.localClippingEnabled = true; // Essential for slicing
    renderer.setSize(containerRef.current.clientWidth, containerRef.current.clientHeight);
    renderer.setPixelRatio(window.devicePixelRatio);
    containerRef.current.appendChild(renderer.domElement);
    rendererRef.current = renderer;

    const controls = new OrbitControls(camera, renderer.domElement);
    controls.enableDamping = true;

    scene.add(new THREE.AmbientLight(0xffffff, 0.5));
    const dl = new THREE.DirectionalLight(0xffffff, 1);
    dl.position.set(100, 100, 100);
    scene.add(dl);

    scene.add(new THREE.GridHelper(400, 40, 0x334155, 0x1e293b));

    const animate = () => {
      requestAnimationFrame(animate);
      controls.update();
      renderer.render(scene, camera);
    };
    animate();

    const handleResize = () => {
      if (!containerRef.current || !cameraRef.current || !rendererRef.current) return;
      cameraRef.current.aspect = containerRef.current.clientWidth / containerRef.current.clientHeight;
      cameraRef.current.updateProjectionMatrix();
      rendererRef.current.setSize(containerRef.current.clientWidth, containerRef.current.clientHeight);
    };
    window.addEventListener('resize', handleResize);

    return () => {
      window.removeEventListener('resize', handleResize);
      renderer.dispose();
      if (containerRef.current) containerRef.current.removeChild(renderer.domElement);
    };
  }, []);

  // Update Plane Helper
  useEffect(() => {
    if (!sceneRef.current) return;
    if (planeHelperRef.current) sceneRef.current.remove(planeHelperRef.current);

    if (state.slice.enabled && state.stats) {
      const planeGeo = new THREE.PlaneGeometry(
        state.stats.boundingBox.size.x * 2,
        state.stats.boundingBox.size.y * 2
      );
      const planeMat = new THREE.MeshBasicMaterial({
        color: 0x3b82f6,
        transparent: true,
        opacity: 0.2,
        side: THREE.DoubleSide
      });
      const helper = new THREE.Mesh(planeGeo, planeMat);

      if (state.slice.axis === 'x') helper.rotation.y = Math.PI / 2;
      if (state.slice.axis === 'y') helper.rotation.x = Math.PI / 2;

      const pos = { x: 0, y: 0, z: 0 };
      (pos as any)[state.slice.axis] = state.slice.position;
      helper.position.set(pos.x, pos.y, pos.z);

      planeHelperRef.current = helper;
      sceneRef.current.add(helper);
    }
  }, [state.slice, state.stats]);

  useEffect(() => {
    if (!sceneRef.current || !geometry) return;

    if (meshRef.current) {
      sceneRef.current.remove(meshRef.current);
      meshRef.current.geometry.dispose();
      (meshRef.current.material as THREE.Material).dispose();
    }

    const clippingPlanes: THREE.Plane[] = [];
    if (state.slice.enabled) {
      const normal = new THREE.Vector3();
      if (state.slice.axis === 'x') normal.set(-1, 0, 0);
      else if (state.slice.axis === 'y') normal.set(0, -1, 0);
      else normal.set(0, 0, -1);

      clippingPlanes.push(new THREE.Plane(normal, state.slice.position));
    }

    const materialProps = {
      color: state.color,
      flatShading: true,
      side: THREE.DoubleSide,
      clippingPlanes: clippingPlanes,
      clipShadows: true
    };

    let material: THREE.Material;
    if (state.viewMode === 'wireframe') material = new THREE.MeshBasicMaterial({ ...materialProps, wireframe: true });
    else if (state.viewMode === 'points') material = new THREE.PointsMaterial({ color: state.color, size: 2 });
    else material = new THREE.MeshPhongMaterial({ ...materialProps, shininess: 30 });

    const mesh = new THREE.Mesh(geometry, material);
    geometry.center();
    meshRef.current = mesh;
    sceneRef.current.add(mesh);
  }, [geometry, state.viewMode, state.color, state.slice]);

  useEffect(() => {
    if (!meshRef.current) return;
    meshRef.current.position.set(state.transform.position.x, state.transform.position.y, state.transform.position.z);
    meshRef.current.rotation.set(
      THREE.MathUtils.degToRad(state.transform.rotation.x),
      THREE.MathUtils.degToRad(state.transform.rotation.y),
      THREE.MathUtils.degToRad(state.transform.rotation.z)
    );
    meshRef.current.scale.setScalar(state.transform.scale);
  }, [state.transform]);

  return <div ref={containerRef} className="w-full h-full relative" />;
};

export default Viewer;

