import React, { useState, useRef } from 'react';
import * as THREE from 'three';
import { Upload, Box, Github, HelpCircle } from 'lucide-react';
import Viewer from './components/Viewer';
import Controls from './components/Controls';
import { AppState, TransformationState, SliceState } from './types';
import { stlService } from './services/stlService';

const INITIAL_TRANSFORM: TransformationState = {
  position: { x: 0, y: 0, z: 0 },
  rotation: { x: 0, y: 0, z: 0 },
  scale: 1
};

const INITIAL_SLICE: SliceState = {
  enabled: false,
  axis: 'z',
  position: 0
};

const INITIAL_STATE: AppState = {
  isLoaded: false,
  fileName: null,
  transform: INITIAL_TRANSFORM,
  slice: INITIAL_SLICE,
  stats: null,
  viewMode: 'solid',
  color: '#3b82f6',
};

const App: React.FC = () => {
  const [state, setState] = useState<AppState>(INITIAL_STATE);
  const [geometry, setGeometry] = useState<THREE.BufferGeometry | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    try {
      const buffer = await file.arrayBuffer();
      const geo = await stlService.loadFromBuffer(buffer);
      const stats = stlService.calculateStats(geo);

      setGeometry(geo);
      setState(prev => ({
        ...prev,
        isLoaded: true,
        fileName: file.name,
        stats,
        transform: INITIAL_TRANSFORM,
        slice: { ...INITIAL_SLICE, position: 0 }
      }));
    } catch (err) {
      alert("Fehler beim Laden der STL Datei.");
    }
  };

  const handleAiAnalyze = async () => {
    if (!state.stats) return;
    const analysis = await stlService.analyzeWithAI(state.stats);
    setState(prev => ({ ...prev, aiAnalysis: analysis }));
  };

  const handleExport = (half?: 'top' | 'bottom') => {
    if (!geometry) return;

    const tempMesh = new THREE.Mesh(geometry.clone());
    tempMesh.position.set(state.transform.position.x, state.transform.position.y, state.transform.position.z);
    tempMesh.rotation.set(
      THREE.MathUtils.degToRad(state.transform.rotation.x),
      THREE.MathUtils.degToRad(state.transform.rotation.y),
      THREE.MathUtils.degToRad(state.transform.rotation.z)
    );
    tempMesh.scale.setScalar(state.transform.scale);
    tempMesh.updateMatrixWorld();

    // In a real splitting app, we'd actually delete geometry vertices here.
    // For this prototype, we export the transformed mesh. 
    // True splitting requires complex CSG math which is simulated here by state.

    const blob = stlService.exportMesh(tempMesh);
    const link = document.createElement('a');
    link.href = URL.createObjectURL(blob);
    link.download = half ? `${half}_part_${state.fileName}` : `edited_${state.fileName}`;
    link.click();
  };

  return (
    <div className="flex h-screen w-screen bg-slate-950 text-slate-50 overflow-hidden select-none">
      <aside className="w-80 h-full bg-slate-900 border-r border-slate-800 z-10 shadow-2xl flex flex-col">
        <div className="p-6 border-b border-slate-800 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="bg-blue-600 p-2 rounded-lg">
                <Box size={20} className="text-white" />
            </div>
            <h1 className="font-bold text-lg tracking-tight">STLEdit <span className="text-blue-500">Pro</span></h1>
          </div>
        </div>

        <div className="flex-1 overflow-hidden">
          <Controls 
            state={state}
            onTransformChange={(key, value) => setState(prev => ({ ...prev, transform: { ...prev.transform, [key]: value }}))}
            onSliceChange={(slice) => setState(prev => ({ ...prev, slice }))}
            onViewModeChange={(mode) => setState(prev => ({ ...prev, viewMode: mode }))}
            onColorChange={(color) => setState(prev => ({ ...prev, color }))}
            onReset={() => setState(prev => ({ ...prev, transform: INITIAL_TRANSFORM }))}
            onExport={handleExport}
            onClear={() => { setGeometry(null); setState(INITIAL_STATE); }}
            onAiAnalyze={handleAiAnalyze}
          />
        </div>
      </aside>

      <main className="flex-1 relative bg-slate-950 overflow-hidden">
        <div className="absolute top-6 left-6 z-20 flex gap-4">
            <div className="flex items-center gap-4 bg-slate-900/80 backdrop-blur-md border border-slate-700/50 px-4 py-2 rounded-2xl shadow-xl">
                <input type="file" accept=".stl" onChange={handleFileUpload} ref={fileInputRef} className="hidden" id="stl-upload" />
                <label htmlFor="stl-upload" className="flex items-center gap-2 text-sm font-semibold cursor-pointer text-slate-300 hover:text-white">
                    <Upload size={18} className="text-blue-500" />
                    {state.fileName ? 'Change File' : 'Upload STL'}
                </label>
            </div>
        </div>

        <div className="w-full h-full">
          {state.isLoaded ? (
            <Viewer geometry={geometry} state={state} />
          ) : (
            <div className="w-full h-full flex flex-col items-center justify-center text-slate-500">
              <Box size={48} className="opacity-10 mb-4" />
              <p>Bereit für deine 3D Modelle</p>
            </div>
          )}
        </div>
      </main>
    </div>
  );
};

