    if (!sceneRef.current || !state.stats) return;

    if (planeStartRef.current) sceneRef.current.remove(planeStartRef.current);
    if (planeEndRef.current) sceneRef.current.remove(planeEndRef.current);

    if (state.slice.enabled) {
      const size = Math.max(state.stats.boundingBox.size.x, state.stats.boundingBox.size.y, state.stats.boundingBox.size.z) * 2;
      const planeGeo = new THREE.PlaneGeometry(size, size);

      const matStart = new THREE.MeshBasicMaterial({ color: 0x3b82f6, transparent: true, opacity: 0.15, side: THREE.DoubleSide });
      const matEnd = new THREE.MeshBasicMaterial({ color: 0x6366f1, transparent: true, opacity: 0.15, side: THREE.DoubleSide });

      const helperStart = new THREE.Mesh(planeGeo, matStart);
      const helperEnd = new THREE.Mesh(planeGeo, matEnd);

      const applyAxisRotation = (mesh: THREE.Mesh) => {
        if (state.slice.axis === 'x') mesh.rotation.y = Math.PI / 2;
        if (state.slice.axis === 'y') mesh.rotation.x = Math.PI / 2;
      };

      applyAxisRotation(helperStart);
      applyAxisRotation(helperEnd);

      const posS = { x: 0, y: 0, z: 0 };
      const posE = { x: 0, y: 0, z: 0 };
      (posS as any)[state.slice.axis] = state.slice.start;
      (posE as any)[state.slice.axis] = state.slice.end;

      helperStart.position.set(posS.x, posS.y, posS.z);
      helperEnd.position.set(posE.x, posE.y, posE.z);

      planeStartRef.current = helperStart;
      planeEndRef.current = helperEnd;
      sceneRef.current.add(helperStart);
      sceneRef.current.add(helperEnd);
    }
  }, [state.slice, state.stats]);

  // Update Main Mesh and Clipping
  useEffect(() => {
    if (!sceneRef.current || !geometry) return;

    if (meshRef.current) {
      sceneRef.current.remove(meshRef.current);
      meshRef.current.geometry.dispose();
      (meshRef.current.material as THREE.Material).dispose();
    }

    const clippingPlanes: THREE.Plane[] = [];
    if (state.slice.enabled) {
      // Plane 1: Everything AFTER start
      const normalStart = new THREE.Vector3();
      if (state.slice.axis === 'x') normalStart.set(-1, 0, 0);
      else if (state.slice.axis === 'y') normalStart.set(0, -1, 0);
      else normalStart.set(0, 0, -1);
      clippingPlanes.push(new THREE.Plane(normalStart, state.slice.end));

      // Plane 2: Everything BEFORE end
      const normalEnd = new THREE.Vector3();
      if (state.slice.axis === 'x') normalEnd.set(1, 0, 0);
      else if (state.slice.axis === 'y') normalEnd.set(0, 1, 0);
      else normalEnd.set(0, 0, 1);
      clippingPlanes.push(new THREE.Plane(normalEnd, -state.slice.start));
    }

    const materialProps = {
      color: state.color,
      flatShading: true,
      side: THREE.DoubleSide,
      clippingPlanes: clippingPlanes,
      clipIntersection: false, // Standard intersection logic for volume
      clipShadows: true
    };

    let material: THREE.Material;
    if (state.viewMode === 'wireframe') material = new THREE.MeshBasicMaterial({ ...materialProps, wireframe: true });
    else if (state.viewMode === 'points') material = new THREE.PointsMaterial({ color: state.color, size: 2 });
    else material = new THREE.MeshPhongMaterial({ ...materialProps, shininess: 30 });

    const mesh = new THREE.Mesh(geometry, material);
    geometry.center();
    meshRef.current = mesh;
    sceneRef.current.add(mesh);
  }, [geometry, state.viewMode, state.color, state.slice]);

  useEffect(() => {
    if (!meshRef.current) return;
    meshRef.current.position.set(state.transform.position.x, state.transform.position.y, state.transform.position.z);
    meshRef.current.rotation.set(
      THREE.MathUtils.degToRad(state.transform.rotation.x),
      THREE.MathUtils.degToRad(state.transform.rotation.y),
      THREE.MathUtils.degToRad(state.transform.rotation.z)
    );
    meshRef.current.scale.setScalar(state.transform.scale);
  }, [state.transform]);

  return <div ref={containerRef} className="w-full h-full relative" />;
};

export default Viewer;

import React, { useState } from 'react';
import { AppState, Vector3, SliceState } from '../types';
import { Download, Trash2, Box, Layers, Move, RefreshCw, Scissors, Sparkles, Loader2, ArrowRightLeft } from 'lucide-react';

interface ControlsProps {
  state: AppState;
  onTransformChange: (key: 'position' | 'rotation' | 'scale', value: any) => void;
  onSliceChange: (slice: SliceState) => void;
  onViewModeChange: (mode: AppState['viewMode']) => void;
  onColorChange: (color: string) => void;
  onReset: () => void;
  onExport: (mode?: 'full' | 'slice') => void;
  onClear: () => void;
  onAiAnalyze: () => void;
}

const ControlGroup: React.FC<{ title: string; icon: React.ReactNode; children: React.ReactNode }> = ({ title, icon, children }) => (
  <div className="mb-4 p-4 bg-slate-800/50 rounded-xl border border-slate-700/50">
    <div className="flex items-center gap-2 mb-4 text-slate-300 font-semibold text-[10px] uppercase tracking-widest">
      {icon}
      <span>{title}</span>
    </div>
    {children}
  </div>
);

const Slider: React.FC<{ label: string; value: number; min: number; max: number; step?: number; color?: string; onChange: (v: number) => void }> = ({ label, value, min, max, step = 0.1, color = "accent-blue-500", onChange }) => (
  <div className="mb-3">
    <div className="flex justify-between text-[10px] text-slate-400 mb-1">
      <span>{label}</span>
      <span className="font-mono">{value.toFixed(2)}</span>
    </div>
    <input
      type="range"
      min={min}
      max={max}
      step={step}
      value={value}
      onChange={(e) => onChange(parseFloat(e.target.value))}
      className={`w-full h-1.5 bg-slate-700 rounded-lg appearance-none cursor-pointer ${color}`}
    />
  </div>
);

const Controls: React.FC<ControlsProps> = ({ state, onTransformChange, onSliceChange, onViewModeChange, onColorChange, onReset, onExport, onClear, onAiAnalyze }) => {
  const [analyzing, setAnalyzing] = useState(false);

  if (!state.isLoaded) return (
      <div className="p-8 text-center text-slate-400">
          <Box className="mx-auto mb-4 opacity-20" size={64} />
          <p className="text-sm">Lade eine STL Datei hoch, um zu beginnen.</p>
      </div>
  );

  const stats = state.stats;
  const boundMin = stats ? Math.min(stats.boundingBox.min.x, stats.boundingBox.min.y, stats.boundingBox.min.z) - 50 : -100;
  const boundMax = stats ? Math.max(stats.boundingBox.max.x, stats.boundingBox.max.y, stats.boundingBox.max.z) + 50 : 100;

  return (
    <div className="flex flex-col h-full overflow-y-auto px-4 py-6 scrollbar-hide">
      <div className="flex justify-between items-center mb-6">
        <h2 className="text-xl font-bold text-white flex items-center gap-2">
            <Box className="text-blue-400" size={20} />
            Editor
        </h2>
        <button onClick={onClear} className="p-2 text-slate-500 hover:text-red-400 transition-colors">
            <Trash2 size={18} />
        </button>
      </div>

