              }`}
            >
              {mode}
            </button>
          ))}
        </div>
        <Slider label="Scale" value={state.transform.scale} min={0.1} max={5} step={0.01} onChange={(v) => onTransformChange('scale', v)} />
      </ControlGroup>

      <div className="mt-auto pt-4 space-y-3">
        <button 
          onClick={onReset}
          className="w-full py-3 flex items-center justify-center gap-2 bg-slate-800 hover:bg-slate-700 text-slate-300 rounded-xl font-semibold text-xs transition-all"
        >
          <RefreshCw size={16} />
          Ansicht zurücksetzen
        </button>
        <button 
          onClick={() => onExport('full')}
          className="w-full py-3 flex items-center justify-center gap-2 bg-blue-600 hover:bg-blue-500 text-white rounded-xl font-bold text-xs shadow-lg shadow-blue-500/30 transition-all"
        >
          <Download size={16} />
          Gesamtes Modell (.stl)
        </button>
      </div>
    </div>
  );
};

