import * as THREE from 'three';
import { STLLoader } from 'three/examples/jsm/loaders/STLLoader';
import { STLExporter } from 'three/examples/jsm/exporters/STLExporter';
import * as BufferGeometryUtils from 'three/examples/jsm/utils/BufferGeometryUtils';
import { MeshStats, SceneObject } from '../types';
import { GoogleGenAI } from "@google/genai";

export class STLService {
  private loader: STLLoader;
  private exporter: STLExporter;

  constructor() {
    this.loader = new STLLoader();
    this.exporter = new STLExporter();
  }

  async loadFromBuffer(buffer: ArrayBuffer): Promise<THREE.BufferGeometry> {
    return this.loader.parse(buffer);
  }

  exportCombined(objects: SceneObject[]): Blob {
    const group = new THREE.Group();

    objects.forEach(obj => {
      if (!obj.visible) return;
      const mesh = new THREE.Mesh(obj.geometry.clone());
      mesh.position.set(obj.transform.position.x, obj.transform.position.y, obj.transform.position.z);
      mesh.rotation.set(
        THREE.MathUtils.degToRad(obj.transform.rotation.x),
        THREE.MathUtils.degToRad(obj.transform.rotation.y),
        THREE.MathUtils.degToRad(obj.transform.rotation.z)
      );
      mesh.scale.setScalar(obj.transform.scale);
      mesh.updateMatrixWorld();
      group.add(mesh);
    });

    const result = this.exporter.parse(group, { binary: true });
    return new Blob([result], { type: 'application/octet-stream' });
  }

  // Clips geometry on CPU for "Baking" parts to the scene
  clipGeometry(geometry: THREE.BufferGeometry, axis: 'x' | 'y' | 'z', start: number, end: number): THREE.BufferGeometry {
    // For a real production app we would use CSG. 
    // Here we perform a simple vertex filtering to create the 'Baked' part.
    const posAttr = geometry.attributes.position;
    const newPositions: number[] = [];

    for (let i = 0; i < posAttr.count; i += 3) {
      const v1 = new THREE.Vector3().fromBufferAttribute(posAttr, i);
      const v2 = new THREE.Vector3().fromBufferAttribute(posAttr, i + 1);
      const v3 = new THREE.Vector3().fromBufferAttribute(posAttr, i + 2);

      const val1 = v1[axis];
      const val2 = v2[axis];
      const val3 = v3[axis];

      // Simple heuristic: If center of triangle is in window, keep it
      const avg = (val1 + val2 + val3) / 3;
      if (avg >= start && avg <= end) {
        newPositions.push(v1.x, v1.y, v1.z, v2.x, v2.y, v2.z, v3.x, v3.y, v3.z);
      }
    }

    const newGeo = new THREE.BufferGeometry();
    newGeo.setAttribute('position', new THREE.Float32BufferAttribute(newPositions, 3));
    newGeo.computeVertexNormals();
    return newGeo;
  }

  async analyzeWithAI(stats: MeshStats): Promise<string> {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const prompt = `Analysiere dieses STL-Modell für den 3D-Druck:
      - Dreiecke: ${stats.triangleCount}
      - Maße: ${stats.boundingBox.size.x.toFixed(1)}x${stats.boundingBox.size.y.toFixed(1)}x${stats.boundingBox.size.z.toFixed(1)}mm
      Gib eine kurze Einschätzung auf Deutsch (max 2 Sätze) zur Druckbarkeit.`;

    try {
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
      });
      return response.text || "Keine Analyse möglich.";
    } catch (e) {
      return "KI Analyse fehlgeschlagen.";
    }
  }

  calculateStats(geometry: THREE.BufferGeometry): MeshStats {
    geometry.computeBoundingBox();
    const box = geometry.boundingBox || new THREE.Box3();
    const size = new THREE.Vector3();
    box.getSize(size);

    const pos = geometry.attributes.position;
    const faces = pos.count / 3;
    let volume = 0;

    for (let i = 0; i < faces; i++) {
      const v1 = new THREE.Vector3().fromBufferAttribute(pos, i * 3 + 0);
      const v2 = new THREE.Vector3().fromBufferAttribute(pos, i * 3 + 1);
      const v3 = new THREE.Vector3().fromBufferAttribute(pos, i * 3 + 2);
      volume += v1.dot(v2.cross(v3)) / 6.0;
    }

    return {
      volume: Math.abs(volume),
      surfaceArea: 0,
      triangleCount: faces,
      boundingBox: {
        min: { x: box.min.x, y: box.min.y, z: box.min.z },
        max: { x: box.max.x, y: box.max.y, z: box.max.z },
        size: { x: size.x, y: size.y, z: size.z }
      }
    };
  }
}

export const stlService = new STLService();

import React, { useEffect, useRef } from 'react';
import * as THREE from 'three';
import { OrbitControls } from 'three/examples/jsm/controls/OrbitControls';
import { AppState } from '../types';

interface ViewerProps {
  state: AppState;
}

const Viewer: React.FC<ViewerProps> = ({ state }) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const rendererRef = useRef<THREE.WebGLRenderer | null>(null);
  const sceneRef = useRef<THREE.Scene | null>(null);
  const cameraRef = useRef<THREE.PerspectiveCamera | null>(null);
  const objectsGroupRef = useRef<THREE.Group | null>(null);
  const helperGroupRef = useRef<THREE.Group | null>(null);

  useEffect(() => {
    if (!containerRef.current) return;

    const scene = new THREE.Scene();
    scene.background = new THREE.Color(0x020617);
    sceneRef.current = scene;

    const camera = new THREE.PerspectiveCamera(45, containerRef.current.clientWidth / containerRef.current.clientHeight, 0.1, 5000);
    camera.position.set(200, 200, 200);
    cameraRef.current = camera;

    const renderer = new THREE.WebGLRenderer({ antialias: true, alpha: true });
    renderer.localClippingEnabled = true;
    renderer.setSize(containerRef.current.clientWidth, containerRef.current.clientHeight);
    renderer.setPixelRatio(window.devicePixelRatio);
    containerRef.current.appendChild(renderer.domElement);
    rendererRef.current = renderer;

    const controls = new OrbitControls(camera, renderer.domElement);
    controls.enableDamping = true;

    scene.add(new THREE.AmbientLight(0xffffff, 0.5));
    const sun = new THREE.DirectionalLight(0xffffff, 1);
    sun.position.set(200, 500, 200);
    scene.add(sun);

    scene.add(new THREE.GridHelper(1000, 50, 0x1e293b, 0x0f172a));

    const objGroup = new THREE.Group();
    scene.add(objGroup);
    objectsGroupRef.current = objGroup;

    const helperGroup = new THREE.Group();
    scene.add(helperGroup);
    helperGroupRef.current = helperGroup;

    const animate = () => {
      requestAnimationFrame(animate);
      controls.update();
      renderer.render(scene, camera);
    };
    animate();

    const handleResize = () => {
      if (!containerRef.current || !cameraRef.current || !rendererRef.current) return;
      cameraRef.current.aspect = containerRef.current.clientWidth / containerRef.current.clientHeight;
      cameraRef.current.updateProjectionMatrix();
      rendererRef.current.setSize(containerRef.current.clientWidth, containerRef.current.clientHeight);
    };
    window.addEventListener('resize', handleResize);

    return () => {
      window.removeEventListener('resize', handleResize);
      renderer.dispose();
      if (containerRef.current) containerRef.current.removeChild(renderer.domElement);
    };
  }, []);

  // Synchronize Scene Objects
  useEffect(() => {
    if (!objectsGroupRef.current) return;

    // Clear existing meshes
    objectsGroupRef.current.children.forEach(c => {
        if (c instanceof THREE.Mesh) {
            c.geometry.dispose();
            (c.material as THREE.Material).dispose();
        }
    });
    objectsGroupRef.current.clear();

    state.objects.forEach(obj => {
      if (!obj.visible) return;

      const isSelected = obj.id === state.selectedId;
      const clippingPlanes: THREE.Plane[] = [];
      let clipIntersection = false;

      // Only the selected object gets the active slice
      if (isSelected && state.slice.enabled) {
        const axisVec = new THREE.Vector3();
        if (state.slice.axis === 'x') axisVec.set(1, 0, 0);
        else if (state.slice.axis === 'y') axisVec.set(0, 1, 0);
        else axisVec.set(0, 0, 1);

        if (state.slice.mode === 'single') {
            clippingPlanes.push(new THREE.Plane(axisVec.clone().negate(), state.slice.singlePos));
        } else {
            if (state.slice.showMiddle) {
                clippingPlanes.push(new THREE.Plane(axisVec.clone().negate(), state.slice.end));
                clippingPlanes.push(new THREE.Plane(axisVec.clone(), -state.slice.start));
                clipIntersection = false;
            } else {
                clippingPlanes.push(new THREE.Plane(axisVec.clone(), -state.slice.start));
                clippingPlanes.push(new THREE.Plane(axisVec.clone().negate(), state.slice.end));
                clipIntersection = true;
            }
        }
      }

      const matProps: any = {
        color: obj.color,
        side: THREE.DoubleSide,
        flatShading: true,
        clippingPlanes,
        clipIntersection,
        transparent: true,
        opacity: isSelected ? 1 : 0.6
      };

      let material;
      if (state.viewMode === 'wireframe') material = new THREE.MeshBasicMaterial({ ...matProps, wireframe: true });
      else if (state.viewMode === 'points') material = new THREE.PointsMaterial({ color: obj.color, size: 1.5 });
      else material = new THREE.MeshPhongMaterial({ ...matProps, shininess: 40 });

      const mesh = new THREE.Mesh(obj.geometry, material);
      mesh.position.set(obj.transform.position.x, obj.transform.position.y, obj.transform.position.z);
      mesh.rotation.set(
        THREE.MathUtils.degToRad(obj.transform.rotation.x),
        THREE.MathUtils.degToRad(obj.transform.rotation.y),
        THREE.MathUtils.degToRad(obj.transform.rotation.z)
      );
      mesh.scale.setScalar(obj.transform.scale);

      if (isSelected) {
          const box = new THREE.BoxHelper(mesh, 0x3b82f6);
          objectsGroupRef.current?.add(box);
      }

      objectsGroupRef.current?.add(mesh);
    });
  }, [state.objects, state.selectedId, state.slice, state.viewMode]);

  // Slicing Helpers
  useEffect(() => {
    if (!helperGroupRef.current || !state.selectedId) {
        helperGroupRef.current?.clear();
        return;
    }

    helperGroupRef.current.clear();
    const selectedObj = state.objects.find(o => o.id === state.selectedId);
    if (!selectedObj || !state.slice.enabled) return;

    const size = 1000;
    const planeGeo = new THREE.PlaneGeometry(size, size);

    const addPlane = (pos: number, color: number) => {
        const mat = new THREE.MeshBasicMaterial({ color, transparent: true, opacity: 0.15, side: THREE.DoubleSide, depthWrite: false });
        const mesh = new THREE.Mesh(planeGeo, mat);
        if (state.slice.axis === 'x') mesh.rotation.y = Math.PI / 2;
        if (state.slice.axis === 'y') mesh.rotation.x = Math.PI / 2;
        const p = { x: 0, y: 0, z: 0 };
        (p as any)[state.slice.axis] = pos;
        mesh.position.set(p.x, p.y, p.z);
        helperGroupRef.current?.add(mesh);
    };

    if (state.slice.mode === 'single') {
        addPlane(state.slice.singlePos, 0x3b82f6);
    } else {
        addPlane(state.slice.start, 0x3b82f6);
        addPlane(state.slice.end, 0x6366f1);
    }
  }, [state.slice, state.selectedId, state.objects]);

  return <div ref={containerRef} className="w-full h-full" />;
};

export default Viewer;

import React, { useState } from 'react';
import { AppState, SceneObject, SliceState } from '../types';
import { 
  Download, Trash2, Box, Layers, Move, RefreshCw, Scissors, Sparkles, 
  Loader2, Minimize2, Maximize2, Eye, EyeOff, Plus, Copy, Package
} from 'lucide-react';

interface ControlsProps {
  state: AppState;
  onSelect: (id: string | null) => void;
  onUpdateObject: (id: string, updates: Partial<SceneObject>) => void;
  onDeleteObject: (id: string) => void;
  onDuplicateObject: (id: string) => void;
  onSliceChange: (slice: SliceState) => void;
  onBakeSlice: () => void;
  onViewModeChange: (mode: AppState['viewMode']) => void;
  onExportCombined: () => void;
  onAiAnalyze: () => void;
}

const ControlGroup: React.FC<{ title: string; icon: React.ReactNode; children: React.ReactNode }> = ({ title, icon, children }) => (
  <div className="mb-4 p-4 bg-slate-800/40 rounded-xl border border-slate-700/50">
    <div className="flex items-center gap-2 mb-4 text-slate-300 font-semibold text-[10px] uppercase tracking-widest">
      {icon}
      <span>{title}</span>
    </div>
    {children}
  </div>
);

const Slider: React.FC<{ label: string; value: number; min: number; max: number; step?: number; color?: string; onChange: (v: number) => void }> = ({ label, value, min, max, step = 0.1, color = "accent-blue-500", onChange }) => (
  <div className="mb-3">
    <div className="flex justify-between text-[10px] text-slate-400 mb-1">
      <span>{label}</span>
      <span className="font-mono">{value.toFixed(2)}</span>
    </div>
    <input
      type="range"
      min={min}
      max={max}
      step={step}
      value={value}
      onChange={(e) => onChange(parseFloat(e.target.value))}
      className={`w-full h-1 bg-slate-700 rounded-lg appearance-none cursor-pointer ${color}`}
    />
  </div>
);

const Controls: React.FC<ControlsProps> = (props) => {
  const { state, onSelect, onUpdateObject, onDeleteObject, onDuplicateObject, onSliceChange, onBakeSlice, onViewModeChange, onExportCombined, onAiAnalyze } = props;
  const [analyzing, setAnalyzing] = useState(false);
  const selectedObj = state.objects.find(o => o.id === state.selectedId);

  return (
    <div className="flex flex-col h-full overflow-y-auto px-4 py-6 scrollbar-hide">

      {/* 1. SCENE TREE / OBJECTS */}
      <ControlGroup title="Scene Explorer" icon={<Package size={14} />}>
        <div className="space-y-2 max-h-48 overflow-y-auto mb-4 pr-1 scrollbar-hide">
          {state.objects.map(obj => (
            <div 
              key={obj.id} 
              onClick={() => onSelect(obj.id)}
              className={`group flex items-center justify-between p-2 rounded-lg cursor-pointer border transition-all ${
                state.selectedId === obj.id ? 'bg-blue-600/20 border-blue-500/50' : 'bg-slate-900/30 border-transparent hover:border-slate-700'
              }`}
            >
              <div className="flex items-center gap-2 truncate">
                <Box size={14} className={state.selectedId === obj.id ? 'text-blue-400' : 'text-slate-500'} />
                <span className={`text-[11px] truncate ${state.selectedId === obj.id ? 'text-blue-100 font-bold' : 'text-slate-400'}`}>
                  {obj.name}
                </span>
              </div>
              <div className="flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                 <button onClick={(e) => { e.stopPropagation(); onUpdateObject(obj.id, { visible: !obj.visible }); }} className="p-1 hover:text-white text-slate-500">
                    {obj.visible ? <Eye size={12}/> : <EyeOff size={12}/>}
                 </button>
                 <button onClick={(e) => { e.stopPropagation(); onDuplicateObject(obj.id); }} className="p-1 hover:text-white text-slate-500">
                    <Copy size={12}/>
                 </button>
                 <button onClick={(e) => { e.stopPropagation(); onDeleteObject(obj.id); }} className="p-1 hover:text-red-400 text-slate-500">
                    <Trash2 size={12}/>
                 </button>
              </div>
            </div>
          ))}
          {state.objects.length === 0 && <p className="text-[10px] text-slate-600 italic text-center py-2">Keine Objekte vorhanden</p>}
        </div>

        {state.aiAnalysis && (
            <div className="p-2 bg-blue-900/20 border border-blue-800/30 rounded-lg text-[10px] text-blue-200 mb-2 italic">
                {state.aiAnalysis}
            </div>
        )}
        <button 
          disabled={!selectedObj || analyzing}
          onClick={async () => { setAnalyzing(true); await onAiAnalyze(); setAnalyzing(false); }}
          className="w-full py-2 bg-slate-700 hover:bg-slate-600 rounded-lg text-[9px] font-bold flex items-center justify-center gap-2 transition-all disabled:opacity-50"
        >
          {analyzing ? <Loader2 size={12} className="animate-spin" /> : <Sparkles size={12} />}
          KI Druck-Check
        </button>
      </ControlGroup>

      {/* 2. TRANSFORM FOR SELECTED */}
      {selectedObj && (
        <ControlGroup title={`Transform: ${selectedObj.name}`} icon={<Move size={14} />}>
           <Slider label="Skalierung" value={selectedObj.transform.scale} min={0.1} max={5} step={0.01} 
              onChange={(v) => onUpdateObject(selectedObj.id, { transform: { ...selectedObj.transform, scale: v } })} />
           <div className="grid grid-cols-2 gap-x-2">
              <Slider label="Pos X" value={selectedObj.transform.position.x} min={-200} max={200} 
                 onChange={(v) => onUpdateObject(selectedObj.id, { transform: { ...selectedObj.transform, position: { ...selectedObj.transform.position, x: v } } })} />
              <Slider label="Pos Y" value={selectedObj.transform.position.y} min={-200} max={200} 
                 onChange={(v) => onUpdateObject(selectedObj.id, { transform: { ...selectedObj.transform, position: { ...selectedObj.transform.position, y: v } } })} />
           </div>
           <Slider label="Rotation Z" value={selectedObj.transform.rotation.z} min={-180} max={180} 
              onChange={(v) => onUpdateObject(selectedObj.id, { transform: { ...selectedObj.transform, rotation: { ...selectedObj.transform.rotation, z: v } } })} />
        </ControlGroup>
      )}

      {/* 3. SLICING / COMBINER TOOLS */}
      {selectedObj && (
