import React, { useState, useRef } from 'react';
import * as THREE from 'three';
import { Upload, Box, Activity, Package, Scissors, Sparkles, Move, Layers } from 'lucide-react';
import Viewer from './components/Viewer';
import Controls from './components/Controls';
import { AppState, SceneObject, SliceState, TransformationState } from './types';
import { stlService } from './services/stlService';

const INITIAL_SLICE: SliceState = {
  enabled: false,
  mode: 'window',
  axis: 'z',
  singlePos: 0,
  start: -20,
  end: 20,
  showMiddle: true
};

const INITIAL_STATE: AppState = {
  objects: [],
  selectedId: null,
  slice: INITIAL_SLICE,
  viewMode: 'solid',
  globalColor: '#3b82f6',
};

const App: React.FC = () => {
  const [state, setState] = useState<AppState>(INITIAL_STATE);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    try {
      const buffer = await file.arrayBuffer();
      const geo = await stlService.loadFromBuffer(buffer);
      const stats = stlService.calculateStats(geo);

      const newObj: SceneObject = {
        id: Math.random().toString(36).substr(2, 9),
        name: file.name.replace('.stl', ''),
        geometry: geo,
        transform: { position: { x: 0, y: 0, z: 0 }, rotation: { x: 0, y: 0, z: 0 }, scale: 1 },
        visible: true,
        color: '#' + Math.floor(Math.random()*16777215).toString(16).padStart(6, '0'),
        stats
      };

      setState(prev => ({
        ...prev,
        objects: [...prev.objects, newObj],
        selectedId: newObj.id
      }));
    } catch (err) {
      alert("Fehler beim Laden.");
    }
  };

  const handleBakeSlice = () => {
    const selected = state.objects.find(o => o.id === state.selectedId);
    if (!selected || !state.slice.enabled) return;

    // Apply window slice filter to create a physical mesh piece
    const newGeo = stlService.clipGeometry(
        selected.geometry, 
        state.slice.axis, 
        state.slice.mode === 'window' ? state.slice.start : -Infinity,
        state.slice.mode === 'window' ? state.slice.end : state.slice.singlePos
    );

    const newObj: SceneObject = {
        id: Math.random().toString(36).substr(2, 9),
        name: `${selected.name}_Slice`,
        geometry: newGeo,
        transform: { ...selected.transform },
        visible: true,
        color: selected.color,
        stats: stlService.calculateStats(newGeo)
    };

    setState(prev => ({
        ...prev,
        objects: [...prev.objects, newObj],
        selectedId: newObj.id,
        slice: { ...prev.slice, enabled: false }
    }));
  };

  const handleUpdateObject = (id: string, updates: Partial<SceneObject>) => {
      setState(prev => ({
          ...prev,
          objects: prev.objects.map(o => o.id === id ? { ...o, ...updates } : o)
      }));
  };

  const handleDuplicate = (id: string) => {
      const original = state.objects.find(o => o.id === id);
      if (!original) return;
      const copy = { ...original, id: Math.random().toString(36).substr(2, 9), name: `${original.name}_Copy` };
      setState(prev => ({ ...prev, objects: [...prev.objects, copy], selectedId: copy.id }));
  };

  const handleDelete = (id: string) => {
      setState(prev => ({
          ...prev,
          objects: prev.objects.filter(o => o.id !== id),
          selectedId: prev.selectedId === id ? null : prev.selectedId
      }));
  };

  const handleExport = () => {
      const blob = stlService.exportCombined(state.objects);
      const link = document.createElement('a');
      link.href = URL.createObjectURL(blob);
      link.download = `assembly_${new Date().getTime()}.stl`;
      link.click();
  };

  return (
    <div className="flex h-screen w-screen bg-slate-950 text-slate-50 overflow-hidden">
      <aside className="w-80 h-full bg-slate-900 border-r border-slate-800 z-10 shadow-2xl flex flex-col">
        <div className="p-6 border-b border-slate-800 flex items-center justify-between">
            <div className="flex items-center gap-3">
              <div className="bg-blue-600 p-2 rounded-lg"><Activity size={20} /></div>
              <h1 className="font-bold text-lg">STL <span className="text-blue-500">Combiner</span></h1>
            </div>
        </div>

        <div className="flex-1 overflow-hidden">
          <Controls 
            state={state}
            onSelect={(id) => setState(prev => ({ ...prev, selectedId: id }))}
            onUpdateObject={handleUpdateObject}
            onDeleteObject={handleDelete}
            onDuplicateObject={handleDuplicate}
            onSliceChange={(slice) => setState(prev => ({ ...prev, slice }))}
            onBakeSlice={handleBakeSlice}
            onViewModeChange={(mode) => setState(prev => ({ ...prev, viewMode: mode }))}
            onExportCombined={handleExport}
            onAiAnalyze={async () => {
                const sel = state.objects.find(o => o.id === state.selectedId);
                if (sel) {
                    const res = await stlService.analyzeWithAI(sel.stats);
                    setState(prev => ({ ...prev, aiAnalysis: res }));
                }
            }}
          />
        </div>
      </aside>

      <main className="flex-1 relative bg-slate-950">
        <div className="absolute top-6 left-6 z-20 flex gap-4">
            <div className="flex items-center gap-4 bg-slate-900/80 backdrop-blur-xl border border-slate-800/50 px-5 py-2.5 rounded-2xl shadow-2xl">
                <input type="file" accept=".stl" onChange={handleFileUpload} ref={fileInputRef} className="hidden" id="stl-upload" />
                <label htmlFor="stl-upload" className="flex items-center gap-2.5 text-sm font-bold cursor-pointer text-slate-300 hover:text-white transition-all group">
                    <Upload size={18} className="text-blue-500 group-hover:scale-110 transition-transform" />
                    Teil hinzufügen
                </label>
            </div>
        </div>

        <div className="w-full h-full">
           <Viewer state={state} />
           {state.objects.length === 0 && (
               <div className="absolute inset-0 flex flex-col items-center justify-center space-y-4 pointer-events-none opacity-30">
                   <Package size={80} />
                   <p className="text-sm font-mono tracking-widest uppercase">Assembly Area Leer</p>
               </div>
           )}
        </div>

        {state.objects.length > 0 && (
            <div className="absolute bottom-6 left-1/2 -translate-x-1/2 z-20 flex items-center gap-4 bg-slate-900/60 backdrop-blur-md px-6 py-2 rounded-full border border-slate-800/50 text-[10px] text-slate-400 font-mono shadow-xl">
               <span className="flex items-center gap-1.5"><div className="w-1.5 h-1.5 rounded-full bg-blue-500" /> PARTS: {state.objects.length}</span>
               <div className="w-px h-3 bg-slate-700" />
               <span className="flex items-center gap-1.5 text-blue-300">ACTIVE: {state.objects.find(o=>o.id===state.selectedId)?.name || 'NONE'}</span>
            </div>
        )}
      </main>
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect } from 'react';
import * as THREE from 'three';
import { Upload, Box, Activity, Package, Scissors, Sparkles, Move, Layers, UploadCloud } from 'lucide-react';
import Viewer from './components/Viewer';
import Controls from './components/Controls';
import { AppState, SceneObject, SliceState, TransformationState } from './types';
import { stlService } from './services/stlService';

const INITIAL_SLICE: SliceState = {
  enabled: false,
  mode: 'window',
  axis: 'z',
  singlePos: 0,
  start: -20,
  end: 20,
  showMiddle: true
};

const INITIAL_STATE: AppState = {
  objects: [],
  selectedId: null,
  slice: INITIAL_SLICE,
  viewMode: 'solid',
  globalColor: '#3b82f6',
};

const App: React.FC = () => {
  const [state, setState] = useState<AppState>(INITIAL_STATE);
  const [isDragging, setIsDragging] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const dragCounter = useRef(0);

  const processFile = async (file: File) => {
    if (!file.name.toLowerCase().endsWith('.stl')) return;

    try {
      const buffer = await file.arrayBuffer();
      const geo = await stlService.loadFromBuffer(buffer);
      const stats = stlService.calculateStats(geo);

      const newObj: SceneObject = {
        id: Math.random().toString(36).substr(2, 9),
        name: file.name.replace('.stl', ''),
        geometry: geo,
        transform: { position: { x: 0, y: 0, z: 0 }, rotation: { x: 0, y: 0, z: 0 }, scale: 1 },
        visible: true,
        color: '#' + Math.floor(Math.random()*16777215).toString(16).padStart(6, '0'),
        stats
      };

      setState(prev => ({
        ...prev,
        objects: [...prev.objects, newObj],
        selectedId: newObj.id
      }));
    } catch (err) {
      console.error("Error loading STL:", err);
    }
  };

  const handleFileUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const files = event.target.files;
    if (!files) return;
    for (const file of Array.from(files)) {
      await processFile(file);
    }
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const handleDragEnter = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    dragCounter.current++;
    if (e.dataTransfer.items && e.dataTransfer.items.length > 0) {
      setIsDragging(true);
    }
  };

  const handleDragLeave = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    dragCounter.current--;
    if (dragCounter.current === 0) {
      setIsDragging(false);
    }
  };

  const handleDragOver = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
  };

  const handleDrop = async (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setIsDragging(false);
    dragCounter.current = 0;

    const files = e.dataTransfer.files;
    if (files && files.length > 0) {
      for (const file of Array.from(files)) {
        await processFile(file);
      }
    }
  };

  const handleBakeSlice = () => {
    const selected = state.objects.find(o => o.id === state.selectedId);
    if (!selected || !state.slice.enabled) return;

    const newGeo = stlService.clipGeometry(
        selected.geometry, 
        state.slice.axis, 
        state.slice.mode === 'window' ? state.slice.start : -Infinity,
        state.slice.mode === 'window' ? state.slice.end : state.slice.singlePos
    );

    const newObj: SceneObject = {
        id: Math.random().toString(36).substr(2, 9),
        name: `${selected.name}_Slice`,
        geometry: newGeo,
        transform: { ...selected.transform },
        visible: true,
        color: selected.color,
        stats: stlService.calculateStats(newGeo)
    };

    setState(prev => ({
        ...prev,
        objects: [...prev.objects, newObj],
        selectedId: newObj.id,
        slice: { ...prev.slice, enabled: false }
    }));
  };

  const handleUpdateObject = (id: string, updates: Partial<SceneObject>) => {
      setState(prev => ({
          ...prev,
          objects: prev.objects.map(o => o.id === id ? { ...o, ...updates } : o)
      }));
  };

  const handleDuplicate = (id: string) => {
      const original = state.objects.find(o => o.id === id);
      if (!original) return;
      const copy = { ...original, id: Math.random().toString(36).substr(2, 9), name: `${original.name}_Copy` };
      setState(prev => ({ ...prev, objects: [...prev.objects, copy], selectedId: copy.id }));
  };

  const handleDelete = (id: string) => {
      setState(prev => ({
          ...prev,
          objects: prev.objects.filter(o => o.id !== id),
          selectedId: prev.selectedId === id ? null : prev.selectedId
      }));
  };

  const handleExport = () => {
      const blob = stlService.exportCombined(state.objects);
      const link = document.createElement('a');
      link.href = URL.createObjectURL(blob);
      link.download = `assembly_${new Date().getTime()}.stl`;
      link.click();
  };

  return (
    <div 
      className="flex h-screen w-screen bg-slate-950 text-slate-50 overflow-hidden relative"
      onDragEnter={handleDragEnter}
      onDragLeave={handleDragLeave}
      onDragOver={handleDragOver}
      onDrop={handleDrop}
    >
      {/* Drag and Drop Overlay */}
      {isDragging && (
        <div className="absolute inset-0 z-[100] flex items-center justify-center bg-blue-600/20 backdrop-blur-sm border-4 border-dashed border-blue-500 m-4 rounded-3xl pointer-events-none animate-in fade-in duration-200">
          <div className="flex flex-col items-center gap-4 text-white">
            <div className="bg-blue-600 p-6 rounded-full shadow-2xl animate-bounce">
              <UploadCloud size={48} />
            </div>
            <div className="text-center">
              <h2 className="text-2xl font-bold tracking-tight">Dateien hier ablegen</h2>
              <p className="text-blue-200 text-sm mt-1">STL Modelle werden automatisch zur Szene hinzugefügt</p>
            </div>
          </div>
        </div>
      )}

      <aside className="w-80 h-full bg-slate-900 border-r border-slate-800 z-10 shadow-2xl flex flex-col">
        <div className="p-6 border-b border-slate-800 flex items-center justify-between">
            <div className="flex items-center gap-3">
              <div className="bg-blue-600 p-2 rounded-lg shadow-lg shadow-blue-600/20"><Activity size={20} /></div>
              <h1 className="font-bold text-lg tracking-tight">STL <span className="text-blue-500">Combiner</span></h1>
            </div>
        </div>

        <div className="flex-1 overflow-hidden">
          <Controls 
            state={state}
            onSelect={(id) => setState(prev => ({ ...prev, selectedId: id }))}
            onUpdateObject={handleUpdateObject}
            onDeleteObject={handleDelete}
            onDuplicateObject={handleDuplicate}
            onSliceChange={(slice) => setState(prev => ({ ...prev, slice }))}
            onBakeSlice={handleBakeSlice}
            onViewModeChange={(mode) => setState(prev => ({ ...prev, viewMode: mode }))}
            onExportCombined={handleExport}
            onAiAnalyze={async () => {
                const sel = state.objects.find(o => o.id === state.selectedId);
                if (sel) {
                    const res = await stlService.analyzeWithAI(sel.stats);
                    setState(prev => ({ ...prev, aiAnalysis: res }));
                }
            }}
          />
        </div>
      </aside>

      <main className="flex-1 relative bg-slate-950">
        <div className="absolute top-6 left-6 z-20 flex gap-4">
            <div className="flex items-center gap-4 bg-slate-900/80 backdrop-blur-xl border border-slate-800/50 px-5 py-2.5 rounded-2xl shadow-2xl transition-all hover:border-blue-500/50">
                <input type="file" accept=".stl" multiple onChange={handleFileUpload} ref={fileInputRef} className="hidden" id="stl-upload" />
                <label htmlFor="stl-upload" className="flex items-center gap-2.5 text-sm font-bold cursor-pointer text-slate-300 hover:text-white transition-all group">
                    <Upload size={18} className="text-blue-500 group-hover:scale-110 transition-transform" />
                    Teile hinzufügen
                </label>
            </div>
        </div>

        <div className="w-full h-full">
           <Viewer state={state} />
           {state.objects.length === 0 && (
               <div className="absolute inset-0 flex flex-col items-center justify-center space-y-6 pointer-events-none">
                   <div className="relative">
                       <div className="absolute inset-0 bg-blue-500/20 blur-3xl rounded-full" />
                       <Package size={80} className="text-slate-700 relative" />
                   </div>
                   <div className="text-center space-y-2 opacity-40">
                       <p className="text-sm font-mono tracking-widest uppercase font-bold">Assembly Area Leer</p>
                       <p className="text-xs">Ziehen Sie STL-Dateien direkt in dieses Fenster</p>
                   </div>
               </div>
           )}
        </div>

        {state.objects.length > 0 && (
            <div className="absolute bottom-6 left-1/2 -translate-x-1/2 z-20 flex items-center gap-4 bg-slate-900/60 backdrop-blur-md px-6 py-2.5 rounded-full border border-slate-800/50 text-[10px] text-slate-400 font-mono shadow-xl">
               <span className="flex items-center gap-1.5"><div className="w-1.5 h-1.5 rounded-full bg-blue-500" /> PARTS: {state.objects.length}</span>
               <div className="w-px h-3 bg-slate-700" />
               <span className="flex items-center gap-1.5 text-blue-300 font-bold">ACTIVE: {state.objects.find(o=>o.id===state.selectedId)?.name || 'NONE'}</span>
            </div>
        )}
      </main>
    </div>
  );
};

